from typing import List

def add_operators(num: str, target: int) -> List[str]:
    result: List[str] = []

    def backtrack(index: int, value: int, prev: int, expr: str) -> None:
        if index == len(num):
            if value == target:
                result.append(expr)
            return
        for i in range(index, len(num)):
            if i != index and num[index] == '0':
                break
            curr = int(num[index:i + 1])
            if index == 0:
                backtrack(i + 1, curr, curr, str(curr))
            else:
                backtrack(i + 1, value + curr, curr, expr + '+' + str(curr))
                backtrack(i + 1, value - curr, -curr, expr + '-' + str(curr))
                backtrack(i + 1, value - prev + prev * curr, prev * curr, expr + '*' + str(curr))

    backtrack(0, 0, 0, '')
    return result
